script.text:
      &ScriptVoucherInit;

function init$Voucher$(f) {initialize(f, 'ong_ba', 'ma_gd', 'loai_ct', 'status');&InitFormVisibleField;}
function active$Voucher$(f) {&ScriptActiveVoucher;&CancelStatusDefault;
  f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
  f._tabContainer._loaded = true;
  &EISetFieldsReadOnly;&EISetFormButtonEdit;&LoadFormVisibleField;
  &VoucherLogHandleStatus;
  &ListCreate;
  &PostCreate;
}
function scatter$Voucher$(f) {&ScriptScatterVoucher;&CancelStatusDefault;&EISetFieldsReadOnly;&EISetFormButtonEdit;&VoucherLogHandleStatus;}
function close$Voucher$(f) {&ScriptCloseVoucher;
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
  &ListDispose;
  &PostDispose;
}
function on$Voucher$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('d84')._controlBehavior;
  switch (action) {
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');
      break;
    case 'Explore':
      &CancelStatusExplore;
      &VoucherLogHandleStatusExplore;
      break;
    case 'Shown':
      &ListShown;
      &PostShown;
      break;
    default:
      break;
  }
}

      &ScriptVoucherNumber;

objectBehavior$Voucher$Currency = {
&ScriptCurrency;
  create: function(f) {
    var d = f.getItem('ngay_lct'), p = f.getItem('ngay_ct'), c = f.getItem('ma_nt'), r = f.getItem('ty_gia'), g = f.getItem('d84')._controlBehavior;
    var v = f._currencyBehavior = $create(FastBusiness.AjaxControlExtender.Currency, {id: f._id + '_currencyBehavior', currencyDate: d, referenceDate: p, exchangeRate: r, form: f, baseCurrency: f._baseCurrency, flush: true}, null, null, c);
    v.set_currencyFields('t_tien_nt&InternalTransportFormMasterForeignCurrencySalesAmount;:t_tien&InternalTransportFormMasterBaseCurrencySalesAmount;');
    v.addGridFields(g, 'gia_nt,tien_nt&InternalTransportFormDetailForeignCurrencySalesAmount;:gia,tien&InternalTransportFormDetailBaseCurrencySalesAmount;');
    v.addTotalFields(g, [['t_tien_nt', 'tien_nt'], ['t_tien', 'tien']]);
    v.set_referenceFields(null);
&CurrencyDateChanged;
  onCurrencySelected: function(sender, e) {
    var f = sender.get_element().parentForm;
    if (e.object._baseCurrency == e.type) {
      focus$Voucher$Tab(f, true);
      &PostCurrencySelected;
    }
  }
}



function onChange$Voucher$Tab(sender, e) {focus$Voucher$Tab(sender.parentForm);&PostTabFocus;}
function focus$Voucher$Tab(f) {
  if (f._usedEI) f.focusWhenTabChanged(['d84', 'so_ct_goc', 'sd_hddt_yn'&ListTabChange;&PostTabChange;&InternalTransportChangeTab;]);
    else f.focusWhenTabChanged(['d84', 'so_ct_goc'&ListTabChange;&PostTabChange;&InternalTransportChangeTab;]);
}
/* <flatten type="Javascript"> */
function onChange$Voucher$Customer(o) {o.parentForm.request('Customer', 'Customer', ['ma_kh'], o);}
function onChange$Voucher$Transaction(o) {o.parentForm.request('Transaction', 'Transaction', ['ma_gd'], o);}
/* </flatten> */
function on$Voucher$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Loading':
      &VoucherNumberLoading;
      break;
    case 'Scattering':
      &VoucherNumberScattering;
      &ListScattering;
      &PostScattering;
      break;

      &VoucherNumberReading;
      &CurrencyResponse;

    case 'Customer':
      f.setItemControlBehavior('ong_ba', result[0].Value, null, true);
      &EICustomerResponseComplete;
      f.live(f.getItem('ong_ba'));
      break;
    case 'Transaction':
      f.setItemControlBehavior('loai_ct', result[0].Value, null, true);
      break;
    case 'Navigating':
      &ListRefresh;
      &PostRefresh;
      break;
    &ListResponseTicket;
      &EIResponseCompleteChecking;
    default:
        break;
  }
}
/* <flatten type="Javascript"> */
function when$VoucherCopying(f) {
  f.setItemValue('stt_rec', '');
  if (f._usedEI) {
    var o = f.getItem('sd_hddt_yn');
    if (o) {f.setItemValue('sd_hddt_yn', '0');}
  }
}
/* </flatten> */
